#include<bits/stdc++.h>
using namespace std;
int t[6005];
int main()
{
	int n, k;
	cin >> n >> k;
	for(int i = 1; i <= n; i++){
		int a;
		cin >> a;
		t[a]++;
		int x = max(1, i * k / 100);
		for(int j = 600; j >= 0; j--){
//			cout << j << endl;
			if(t[j])x -= t[j];
			if(x <= 0){
				cout << j << " ";
				break;
			}
		}
	}
}
